module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output reg [WIDTH-1:0]	rdata
);

reg [ADDR_WIDTH-1:0] wptr, rptr;
reg [ADDR_WIDTH:0] wgray, rgray;

wire [ADDR_WIDTH-1:0] waddr, raddr;
wire [WIDTH-1:0] rdata_ram;

dual_port_RAM #(.DEPTH(DEPTH), .WIDTH(WIDTH)) ram (
    .wclk(wclk),
    .wenc(winc),
    .waddr(waddr),
    .wdata(wdata),
    .rclk(rclk),
    .renc(rinc),
    .raddr(raddr),
    .rdata(rdata_ram)
);

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr <= 0;
        wgray <= 0;
    end else if (winc && !wfull) begin
        wptr <= wptr + 1'b1;
        wgray <= (wgray + 1'b1) ^ (wgray << 1);
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr <= 0;
        rgray <= 0;
        rdata <= 0;
    end else if (rinc && !rempty) begin
        rptr <= rptr + 1'b1;
        rgray <= (rgray + 1'b1) ^ (rgray << 1);
        rdata <= rdata_ram;
    end
end

assign waddr = wptr;
assign raddr = rptr;
assign wfull = (wgray[ADDR_WIDTH-1:0] == rgray[ADDR_WIDTH-1:0]) && (wgray[ADDR_WIDTH] != rgray[ADDR_WIDTH]);
assign rempty = (wgray == rgray);

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
